CREATE OR REPLACE FUNCTION pass_payment_fts_match(search_vector tsvector, query text)
RETURNS boolean AS $$
    SELECT coalesce(search_vector @@ dcpass_fts_query(query), false);
$$ LANGUAGE sql IMMUTABLE;

CREATE OR REPLACE FUNCTION pass_payment_fts_rank(search_vector tsvector, query text)
RETURNS real AS $$
    SELECT coalesce(ts_rank(search_vector, dcpass_fts_query(query)), 0);
$$ LANGUAGE sql IMMUTABLE;
